import{_ as s,c as a,o as n,a4 as e}from"./chunks/framework.HaEZziQ1.js";const u=JSON.parse('{"title":"网络基础面试题","description":"","frontmatter":{},"headers":[],"relativePath":"Document/前端面试相关/计算机基础面试题/网络基础面试题.md","filePath":"Document/前端面试相关/计算机基础面试题/网络基础面试题.md","lastUpdated":null}'),l={name:"Document/前端面试相关/计算机基础面试题/网络基础面试题.md"},p=e(`<h1 id="网络基础面试题" tabindex="-1">网络基础面试题 <a class="header-anchor" href="#网络基础面试题" aria-label="Permalink to &quot;网络基础面试题&quot;">​</a></h1><h2 id="get-和-post-的区别" tabindex="-1">GET 和 POST 的区别 <a class="header-anchor" href="#get-和-post-的区别" aria-label="Permalink to &quot;GET 和 POST 的区别&quot;">​</a></h2><p>参考回答： get 参数通过 url 传递，post 放在 request body 中。</p><p>get 请求在 url 中传递的参数是有长度限制的，而 post 没有。</p><p>get 比 post 更不安全，因为参数直接暴露在 url 中，所以不能用来传递敏感信息。</p><p>get 请求只能进行 url 编码，而 post 支持多种编码方式</p><p>get 请求会浏览器主动 cache，而 post 支持多种编码方式。</p><p>get 请求参数会被完整保留在浏览历史记录里，而 post 中的参数不会被保留。</p><p>GET 和 POST 本质上就是 TCP 链接，并无差别。但是由于 HTTP 的规定和浏览器/服务器的限制，导致他们在应用过程中体现出一些不同。</p><p>GET 产生一个 TCP 数据包；POST 产生两个 TCP 数据包。</p><h2 id="fetch-发送-2-次请求的原因" tabindex="-1">fetch 发送 2 次请求的原因 <a class="header-anchor" href="#fetch-发送-2-次请求的原因" aria-label="Permalink to &quot;fetch 发送 2 次请求的原因&quot;">​</a></h2><p>参考回答：</p><p>fetch 发送 post 请求的时候，总是发送 2 次，第一次状态码是 204，第二次才成功？</p><p>原因很简单，因为你用 fetch 的 post 请求的时候，导致 fetch 第一次发送了一个Options 请求，询问服务器是否支持修改的请求头，如果服务器支持，则在第二次中发送真正的请求</p><h2 id="跨域" tabindex="-1">跨域 <a class="header-anchor" href="#跨域" aria-label="Permalink to &quot;跨域&quot;">​</a></h2><p>很多种⽅法，但万变不离其宗，都是为了搞定同源策略。重⽤的有jsonp 、 iframe 、 cors 、 img 、H TML5 postMessage 等等。其中⽤到 html 标签进⾏跨域的原理就是 html 不受同源策略影响。但只是接受Get 的请求⽅式，这个得清楚。</p><p>延伸1：img iframe script 来发送跨域请求有什么优缺点？</p><h3 id="iframe" tabindex="-1">iframe <a class="header-anchor" href="#iframe" aria-label="Permalink to &quot;iframe&quot;">​</a></h3><p>优点：跨域完毕之后 DOM 操作和互相之间的 JavaScript 调⽤都是没有问题的</p><p>缺点：</p><p>1.若结果要以 URL 参数传递，这就意味着在结果数据量很⼤的时候需要分割传递，巨烦。</p><p>2.还有⼀个是 iframe 本身带来的，⺟⻚⾯和 iframe 本身的交互本身就有安全性限制。</p><h3 id="script" tabindex="-1">script <a class="header-anchor" href="#script" aria-label="Permalink to &quot;script&quot;">​</a></h3><p>优点：可以直接返回 json 格式的数据，⽅便处理</p><p>缺点：只接受 GET 请求⽅式</p><h3 id="图片ping" tabindex="-1">图⽚ping <a class="header-anchor" href="#图片ping" aria-label="Permalink to &quot;图⽚ping&quot;">​</a></h3><p>优点：可以访问任何 url ，⼀般⽤来进⾏点击追踪，做⻚⾯分析常⽤的⽅法</p><p>缺点：不能访问响应⽂本，只能监听是否响应</p><p>延伸2：配合 webpack 进⾏反向代理？</p><p>webpack 在 devServer 选项⾥⾯提供了⼀个 proxy 的参数供开发⼈员进⾏反向代理</p><div class="language-json line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#ABB2BF;">&#39;/api&#39;: {</span></span>
<span class="line"><span style="color:#FFFFFF;">    target</span><span style="color:#ABB2BF;">: </span><span style="color:#FFFFFF;">&#39;http:</span><span style="color:#7F848E;font-style:italic;">//www.example.com&#39;, // your target host</span></span>
<span class="line"><span style="color:#FFFFFF;">    changeOrigin:</span><span style="color:#D19A66;"> true</span><span style="color:#ABB2BF;">, </span><span style="color:#7F848E;font-style:italic;">// needed for virtual hosted sites</span></span>
<span class="line"><span style="color:#FFFFFF;">    pathRewrite</span><span style="color:#ABB2BF;">: {</span></span>
<span class="line"><span style="color:#FFFFFF;">    	&#39;^/api&#39;</span><span style="color:#ABB2BF;">: </span><span style="color:#FFFFFF;">&#39;&#39;</span><span style="color:#7F848E;font-style:italic;"> // rewrite path</span></span>
<span class="line"><span style="color:#ABB2BF;">    }</span></span>
<span class="line"><span style="color:#ABB2BF;">},</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>然后再配合 http-proxy-middleware 插件对 api 请求地址进⾏代理</p><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> express</span><span style="color:#56B6C2;"> =</span><span style="color:#61AFEF;"> require</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;express&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> proxy</span><span style="color:#56B6C2;"> =</span><span style="color:#61AFEF;"> require</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;http-proxy-middleware&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// proxy api requests</span></span>
<span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> exampleProxy</span><span style="color:#56B6C2;"> =</span><span style="color:#61AFEF;"> proxy</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">options</span><span style="color:#ABB2BF;">); </span><span style="color:#7F848E;font-style:italic;">// 这⾥的 options 就是 webpack ⾥⾯的 pro</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// mount \`exampleProxy\` in web server</span></span>
<span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> app</span><span style="color:#56B6C2;"> =</span><span style="color:#61AFEF;"> express</span><span style="color:#ABB2BF;">();</span></span>
<span class="line"><span style="color:#E5C07B;">app</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">use</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;/api&#39;</span><span style="color:#ABB2BF;">, </span><span style="color:#E06C75;">exampleProxy</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#E5C07B;">app</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">listen</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">3000</span><span style="color:#ABB2BF;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>然后再⽤ nginx 把允许跨域的源地址添加到报头⾥⾯即可</p><p>说到 nginx ，可以再谈谈 CORS 配置，⼤致如下：</p><div class="language-json line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#ABB2BF;">location / {</span></span>
<span class="line"><span style="color:#FFFFFF;">    if</span><span style="color:#FFFFFF;"> ($request_method</span><span style="color:#FFFFFF;"> =</span><span style="color:#FFFFFF;"> &#39;OPTIONS&#39;)</span><span style="color:#FFFFFF;"> {</span></span>
<span class="line"><span style="color:#FFFFFF;">        add_header</span><span style="color:#FFFFFF;"> &#39;Access-Control-Allow-Origin&#39;</span><span style="color:#FFFFFF;"> &#39;*&#39;;</span><span style="color:#ABB2BF;"> </span></span>
<span class="line"><span style="color:#FFFFFF;">        add_header</span><span style="color:#FFFFFF;"> &#39;Access-Control-Allow-Methods&#39;</span><span style="color:#FFFFFF;"> &#39;GET,</span><span style="color:#FFFFFF;"> POST,</span><span style="color:#FFFFFF;"> OPTIONS&#39;;</span></span>
<span class="line"><span style="color:#FFFFFF;">        add_header</span><span style="color:#FFFFFF;"> &#39;Access-Control-Allow-Credentials&#39;</span><span style="color:#FFFFFF;"> &#39;true&#39;;</span></span>
<span class="line"><span style="color:#FFFFFF;">        add_header</span><span style="color:#FFFFFF;"> &#39;Access-Control-Allow-Headers&#39;</span><span style="color:#FFFFFF;"> &#39;DNT,</span><span style="color:#FFFFFF;"> X-Mx-ReqToken,</span><span style="color:#FFFFFF;"> Keep-Ali</span></span>
<span class="line"><span style="color:#FFFFFF;">        add_header</span><span style="color:#FFFFFF;"> &#39;Access-Control-Max-Age&#39;</span><span style="color:#FFFFFF;"> 86400;</span><span style="color:#ABB2BF;"> </span></span>
<span class="line"><span style="color:#FFFFFF;">        add_header</span><span style="color:#FFFFFF;"> &#39;Content-Type&#39;</span><span style="color:#FFFFFF;"> &#39;text/plain</span><span style="color:#FFFFFF;"> charset=UTF-8&#39;;</span><span style="color:#ABB2BF;"> </span></span>
<span class="line"><span style="color:#FFFFFF;">        add_header</span><span style="color:#FFFFFF;"> &#39;Content-Length&#39;</span><span style="color:#FFFFFF;"> 0;</span><span style="color:#ABB2BF;"> </span></span>
<span class="line"><span style="color:#FFFFFF;">        return</span><span style="color:#FFFFFF;"> 200;</span><span style="color:#ABB2BF;"> </span></span>
<span class="line"><span style="color:#ABB2BF;">    }</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h2 id="http-无状态无连接" tabindex="-1">http ⽆状态⽆连接 <a class="header-anchor" href="#http-无状态无连接" aria-label="Permalink to &quot;http ⽆状态⽆连接&quot;">​</a></h2><ul><li>http 协议对于事务处理没有记忆能⼒</li><li>对同⼀个 url 请求没有上下⽂关系</li><li>每次的请求都是独⽴的，它的执⾏情况和结果与前⾯的请求和之后的请求是⽆直接关系</li><li>的，它不会受前⾯的请求应答情况直接影响，也不会直接影响后⾯的请求应答情况</li><li>服务器中没有保存客户端的状态，客户端必须每次带上⾃⼰的状态去请求服务器</li><li>⼈⽣若只如初⻅，请求过的资源下⼀次会继续进⾏请求</li></ul><h3 id="http协议无状态中的-状态-到底指的是什么" tabindex="-1">http协议⽆状态中的 状态 到底指的是什么？！ <a class="header-anchor" href="#http协议无状态中的-状态-到底指的是什么" aria-label="Permalink to &quot;http协议⽆状态中的 状态 到底指的是什么？！&quot;">​</a></h3><ul><li>【状态】的含义就是：客户端和服务器在某次会话中产⽣的数据</li><li>那么对应的【⽆状态】就意味着：这些数据不会被保留</li><li>通过增加 cookie 和 session 机制，现在的⽹络请求其实是有状态的</li><li>在没有状态的 http 协议下，服务器也⼀定会保留你每次⽹络请求对数据的修=改，但这跟保留每次访问的数据是不⼀样的，保留的只是会话产⽣的结果，⽽没有保留会话</li></ul><h2 id="http-cache-就是-http-缓存" tabindex="-1">http-cache：就是 http 缓存 <a class="header-anchor" href="#http-cache-就是-http-缓存" aria-label="Permalink to &quot;http-cache：就是 http 缓存&quot;">​</a></h2><h3 id="_1-首先得明确-http-缓存的好处" tabindex="-1">1.⾸先得明确 http 缓存的好处 <a class="header-anchor" href="#_1-首先得明确-http-缓存的好处" aria-label="Permalink to &quot;1.⾸先得明确 http 缓存的好处&quot;">​</a></h3><ul><li>减少了冗余的数据传输，减少⽹费</li><li>减少服务器端的压⼒</li><li>Web 缓存能够减少延迟与⽹络阻塞，进⽽减少显示某个资源所⽤的时间</li><li>加快客户端加载⽹⻚的速度</li></ul><h3 id="_2-常⻅-http-缓存的类型" tabindex="-1">2.常⻅ http 缓存的类型 <a class="header-anchor" href="#_2-常⻅-http-缓存的类型" aria-label="Permalink to &quot;2.常⻅ http 缓存的类型&quot;">​</a></h3><ul><li>私有缓存（⼀般为本地浏览器缓存）</li><li>代理缓存</li></ul><h3 id="_3-然后谈谈本地缓存" tabindex="-1">3.然后谈谈本地缓存 <a class="header-anchor" href="#_3-然后谈谈本地缓存" aria-label="Permalink to &quot;3.然后谈谈本地缓存&quot;">​</a></h3><p>本地缓存是指浏览器请求资源时命中了浏览器本地的缓存资源，浏览器并不会 发送真正的请求给服务器了。它的执⾏过程是:</p><ul><li>第⼀次浏览器发送请求给服务器时，此时浏览器还没有本地缓存副本，服务器返回资源给浏览器，响应码是 200 OK ，浏览器收到资源后，把资源和对应的响应头⼀起缓存下来</li><li>第⼆次浏览器准备发送请求给服务器时候，浏览器会先检查上⼀次服务端返回的响应头信息中的 Cache-Control ，它的值是⼀个相对值，单位为秒，表示资源在客户端缓存的最⼤有效期，过期时间为第⼀次请求的时间减去 Cache-Control 的值，过期时间跟当前的请求时间⽐较，如果本地缓存资源没过期，那么命中缓存，不再请求服务器</li><li>如果没有命中，浏览器就会把请求发送给服务器，进⼊缓存协商阶段。</li></ul><p>与本地缓存相关的头有： Cache-Control 、 Expires ， Cache-Control有多个可选值代表不同的意义，⽽ Expires 就是⼀个⽇期格式的绝对值。</p><h4 id="_3-1-cache-control" tabindex="-1">3.1 Cache-Control <a class="header-anchor" href="#_3-1-cache-control" aria-label="Permalink to &quot;3.1 Cache-Control&quot;">​</a></h4><p>Cache-Control 是 HTPP 缓存策略中最重要的头，它是 HTTP/1.1 中出现 的，它由如下⼏个值：</p><ul><li>no-cache ：不使⽤本地缓存。需要使⽤缓存协商，先与服务器确认返回的响应是否被更改，如果之前的响应中存在 ETag ，那么请求的时候会与服务端验证，如果资源未被更改，则可以避免重新下载</li><li>no-store ：直接禁⽌游览器缓存数据，每次⽤户请求该资源，都会向服务器发送⼀个请求，每次都会下载完整的资源</li><li>public ：可以被所有的⽤户缓存，包括终端⽤户和 CDN 等中间代理服务器。</li><li>private ：只能被终端⽤户的浏览器缓存，不允许 CDN 等中继缓存服务器对其缓存。</li><li>max-age ：从当前请求开始，允许获取的响应被重⽤的最⻓时间（秒）。</li></ul><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;"># 例如：</span></span>
<span class="line"><span style="color:#61AFEF;">Cache-Control:</span><span style="color:#98C379;"> public,</span><span style="color:#98C379;"> max-age=</span><span style="color:#D19A66;">1000</span><span style="color:#ABB2BF;"> </span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 表示资源可以被所有⽤户以及代理服务器缓存，最⻓时间为1000秒</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h4 id="_3-2-expires" tabindex="-1">3.2 Expires <a class="header-anchor" href="#_3-2-expires" aria-label="Permalink to &quot;3.2 Expires&quot;">​</a></h4><p>Expires 是 HTTP/1.0 出现的头信息，同样是⽤于决定本地缓存策略的头，它是⼀个绝对时间，时间格式是如 Mon, 10 Jun 2015 21:31:12 GMT ，只要发送请求时间是在 Expires 之前，那么本地缓存始终有效，否则就会去服务器发送请求获取新的资源。如果同时出现 Cache-Control：max-age 和Expires ，那么 max-age 优先级更⾼。他们可以这样组合使⽤</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">Cache-Control:</span><span style="color:#98C379;"> public</span></span>
<span class="line"><span style="color:#61AFEF;">Expires:</span><span style="color:#98C379;"> Wed,</span><span style="color:#98C379;"> Jan</span><span style="color:#D19A66;"> 10</span><span style="color:#D19A66;"> 2018</span><span style="color:#D19A66;"> 00</span><span style="color:#98C379;">:27:04</span><span style="color:#98C379;"> GMT</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h4 id="_3-3-所谓的缓存协商" tabindex="-1">3.3 所谓的缓存协商 <a class="header-anchor" href="#_3-3-所谓的缓存协商" aria-label="Permalink to &quot;3.3 所谓的缓存协商&quot;">​</a></h4><p>当第⼀次请求时服务器返回的响应头中存在以下情况时</p><ul><li>没有 Cache-Control 和 Expires</li><li>Cache-Control 和 Expires 过期了</li><li>Cache-Control 的属性设置为 no-cache 时</li></ul><p>那么浏览器第⼆次请求时就会与服务器进⾏协商，询问浏览器中的缓存资源是不是旧版本，需不需要更新，此时，服务器就会做出判断，如果缓存和服务端资源的最新版本是⼀致的，那么就⽆需再次下载该资源，服务端直接返回 304 Not Modified 状态码，如果服务器发现浏览器中的缓存已经是旧版本了，那么服务器就会把最新资源的完整内容返回给浏览器，状态码就是 200 Ok ，那么服务端是根据什么来判断浏览器的缓存是不是最新的呢？其实是根据 HTTP的另外两组头信息，分别是： Last-Modified/If-Modified-Since 与ETag/If-None-Match 。</p><h5 id="last-modified-与-if-modified-since" tabindex="-1">Last-Modified 与 If-Modified-Since <a class="header-anchor" href="#last-modified-与-if-modified-since" aria-label="Permalink to &quot;Last-Modified 与 If-Modified-Since&quot;">​</a></h5><ul><li>浏览器第⼀次请求资源时，服务器会把资源的最新修改时间 Last-Modified:Thu, 29 Dec 2011 18:23:55 GMT 放在响应头中返回给浏览器</li><li>第⼆次请求时，浏览器就会把上⼀次服务器返回的修改时间放在请求头 If-Modified-Since:Thu, 29 Dec 2011 18:23:55 发送给服务器，服务器就会拿这个时间跟服务器上的资源的最新修改时间进⾏对⽐</li></ul><p>如果两者相等或者⼤于服务器上的最新修改时间，那么表示浏览器的缓存是有 效的，此时缓存会命中，服务器就不再返回内容给浏览器了，同时Last-Modified 头也不会返回，因为资源没被修改，返回了也没什么意义。如果没命中缓存则最新修改的资源连同 Last-Modified 头⼀起返回</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;"># 第⼀次请求返回的响应头</span></span>
<span class="line"><span style="color:#61AFEF;">Cache-Control:max-age</span><span style="color:#ABB2BF;">=3600</span></span>
<span class="line"><span style="color:#61AFEF;">Expires:</span><span style="color:#98C379;"> Fri,</span><span style="color:#98C379;"> Jan</span><span style="color:#D19A66;"> 12</span><span style="color:#D19A66;"> 2018</span><span style="color:#D19A66;"> 00</span><span style="color:#98C379;">:27:04</span><span style="color:#98C379;"> GMT</span></span>
<span class="line"><span style="color:#61AFEF;">Last-Modified:</span><span style="color:#98C379;"> Wed,</span><span style="color:#98C379;"> Jan</span><span style="color:#D19A66;"> 10</span><span style="color:#D19A66;"> 2018</span><span style="color:#D19A66;"> 00</span><span style="color:#98C379;">:27:04</span><span style="color:#98C379;"> GMT</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 第⼆次请求的请求头信息</span></span>
<span class="line"><span style="color:#61AFEF;">If-Modified-Since:</span><span style="color:#98C379;"> Wed,</span><span style="color:#98C379;"> Jan</span><span style="color:#D19A66;"> 10</span><span style="color:#D19A66;"> 2018</span><span style="color:#D19A66;"> 00</span><span style="color:#98C379;">:27:04</span><span style="color:#98C379;"> GMT</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这组头信息是基于资源的修改时间来判断资源有没有更新，另⼀种⽅式就是根 据资源的内容来判断，就是接下来要讨论的 ETag 与 If-None-Match</p><h5 id="etag与if-none-match" tabindex="-1">ETag与If-None-Match <a class="header-anchor" href="#etag与if-none-match" aria-label="Permalink to &quot;ETag与If-None-Match&quot;">​</a></h5><p>ETag/If-None-Match 与 Last-Modified/If-Modified-Since 的流程其实是类似的，唯⼀的区别是它基于资源的内容的摘要信息（⽐如 MD5 hash ）来判断</p><p>浏览器发送第⼆次请求时，会把第⼀次的响应头信息 ETag 的值放在 If-None-Match 的请求头中发送到服务器，与最新的资源的摘要信息对⽐，如果相等，取浏览器缓存，否则内容有更新，最新的资源连同最新的摘要信息返回。⽤ ETag 的好处是如果因为某种原因到时资源的修改时间没改变，那么⽤ ETag 就能区分资源是不是有被更新。</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;"># 第⼀次请求返回的响应头：</span></span>
<span class="line"><span style="color:#61AFEF;">Cache-Control:</span><span style="color:#98C379;"> public,</span><span style="color:#98C379;"> max-age=</span><span style="color:#D19A66;">31536000</span></span>
<span class="line"><span style="color:#61AFEF;">ETag:</span><span style="color:#98C379;"> &quot;15f0fff99ed5aae4edffdd6496d7131f&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 第⼆次请求的请求头信息：</span></span>
<span class="line"><span style="color:#61AFEF;">If-None-Match:</span><span style="color:#98C379;"> &quot;15f0fff99ed5aae4edffdd6496d7131f&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h2 id="cookie-和-session" tabindex="-1">cookie 和 session <a class="header-anchor" href="#cookie-和-session" aria-label="Permalink to &quot;cookie 和 session&quot;">​</a></h2><ul><li>session ： 是⼀个抽象概念，开发者为了实现中断和继续等操作，将 user agent 和server 之间⼀对⼀的交互，抽象为“会话”，进⽽衍⽣出“会话状态”，也就是 session的概念</li><li>cookie ：它是⼀个世纪存在的东⻄， http 协议中定义在 header 中的字段，可以认为是 session 的⼀种后端⽆状态实现</li></ul><p>现在我们常说的 session ，是为了绕开 cookie 的各种限制，通常借助cookie 本身和后端存储实现的，⼀种更⾼级的会话状态实现</p><p>session 的常⻅实现要借助 cookie 来发送 sessionID</p>`,73),o=[p];function r(t,c,i,F,d,h){return n(),a("div",null,o)}const b=s(l,[["render",r]]);export{u as __pageData,b as default};
